VALUES (1, '{"theme":{"primaryColor":"#05c1ff","accentColor":"#f9a11b","heroButtonText":"#ffffff","heroBgImage":"/src/assets/images/hero-bg.png","headerBgImage":"/src/assets/images/mask.png"},"hero":{"titleLine1":"Africa''s development story","titleLine2":"deserves investment-grade visibility","description":"Olympian House International (OHI) turns complex development, ESG, and investment programmes into cinematic proof that builds trust, demonstrates results, and mobilises capital, partnerships, and policy action.","primaryCtaLabel":"Explore Profile","primaryCtaHref":"/company-profile","secondaryCtaLabel":"Our Story","secondaryCtaHref":"/about","stats":[{"value":"100+","label":"Projects delivered","accent":"#f9a11b","barWidth":"150px"},{"value":"70+","label":"Institutional clients served","accent":"#05c1ff","barWidth":"150px"},{"value":"95%","label":"Repeat-client rate","accent":"#0296cc","barWidth":"100px"}],"images":{"hero1":"/src/assets/images/HeroImg/hero1.jpeg","hero2":"/src/assets/images/HeroImg/hero2.jpeg","hero3":"/src/assets/images/HeroImg/hero3.jpeg","hero4":"/src/assets/images/HeroImg/hero4.jpeg","hero5":"/src/assets/images/HeroImg/hero5.jpeg"}},"about":{"title":"Our Story","paragraphs":["Olympian House International was founded in 2015 by filmmaker and development communication specialist Fombang Banns N. on a conviction that has only deepened over a decade of work: the quality of a story is inseparable from the quality of the capital, partnerships, and policy decisions it attracts.","We make Africa''s development and investment journeys visible through strategic, multilingual visual narratives that turn technical programmes into credible proof for institutions, investors, donors, and the communities they serve."],"image":"/src/assets/images/Gallery/gallery-11.jpeg","overlay":{"since":"Since 2015","tagline":"Investment-grade storytelling","trustLabel":"Proof-led","role":"Development, Impact & Investment","icon":"/src/assets/img/logo-ohi-blue.png","avata